function toBase36(num) {
    if (num === 0) return '0';
    let digits = '';
    while (num > 0) {
        let rem = num % 36;
        if (rem < 10) {
            digits = rem + digits;
        } else {
            digits = String.fromCharCode(65 + rem - 10) + digits;
        }
        num = Math.floor(num / 36);
    }
    return digits;
}

function solve(n) {
    const hexPart = (n * n).toString(16).toUpperCase();
    const base36Part = toBase36(n * n * n);
    return hexPart + base36Part;
}

